    // Since roads are bidirectional
    // Edge u -> v
    adj(u).append((v, cost, costWithTax))
    // Edge v -> u
    adj(v).append((u, cost, costWithTax))
  }

  // --- Step 1: Calculate shortest path distances with no apple (D_empty) ---
  // D_empty[i][j]: shortest path cost from i to j without carrying apples.
  // Since the graph is undirected and costs are non-negative, we can use Dijkstra's.
  // We need all-pairs shortest paths for the 'empty' journey.

  val INF = Long.MaxValue / 2 // Use a large but safe value

