  // 1. Empty trip: cost = cost_i
  // 2. Carrying trip: cost = cost_i * tax_i

  // 1. Shortest path *without* apples (Empty journey: i -> j)
  // dist_empty[j] will store the shortest path cost from *any* starting node to j using only 'cost' edges.
  // This is not quite what we need. We need shortest path *between* any two nodes.

  // Since N is small (<= 1000), Floyd-Warshall is O(N^3) which is too slow (10^9).
  // Dijkstra from every node: N * O(E log N) or N * O(N^2) depending on implementation.
  // E <= 2000. N * E log N is fine.

  // dist_empty[i][j]: shortest path cost from i to j when empty.
  val dist_empty = Array.ofDim[Array[Long]](N)
  for (i <- 0 until N) {
    dist_empty(i) = Array.fill(N)(INF)
    dist_empty(i)(i) = 0L
  }

