  for (startNode <- 0 until N) {
    val pq = scala.collection.mutable.PriorityQueue[Pair[Long, Int]]()
    pq.put((0L, startNode))
    dist_empty(startNode)(startNode) = 0L

    while (pq.nonEmpty) {
      val (d, u) = pq.dequeue()

      if (d > dist_empty(startNode)(u)) continue

      for ((v, cost, _) <- adj(u)) {
        val newDist = d + cost
        if (newDist < dist_empty(startNode)(v)) {
          dist_empty(startNode)(v) = newDist
          pq.put((newDist, v))
        }
      }
    }
