  for (startNode <- 0 until N) {
    val pq = scala.collection.mutable.PriorityQueue[Pair[Long, Int]]()
    pq.put((0L, startNode))
    dist_carrying(startNode)(startNode) = 0L

    while (pq.nonEmpty) {
      val (d, u) = pq.dequeue()

      if (d > dist_carrying(startNode)(u)) continue

      for ((v, _, costWithTax) <- adj(u)) {
        val newDist = d + costWithTax
        if (newDist < dist_carrying(startNode)(v)) {
          dist_carrying(startNode)(v) = newDist
          pq.put((newDist, v))
        }
      }
    }
  }

  // --- Step 3: Calculate the minimum cost for each shop i ---
  val ans = Array.fill(N)(INF)

  for (i <- 0 until N) {
    // Option 1: Buy directly at i
    var minCost = prices(i)

    // Option 2: Travel i -> j (empty), buy at j, travel j -> i (carrying)
    for (j <- 0 until N) {
      if (i == j) continue

      // Cost = Price[j] + Cost(i -> j, empty) + Cost(j -> i, carrying)

      val costEmptyIJ = dist_empty(i)(j)
      val costCarryingJI = dist_carrying(j)(i)

