    * @param n The number of stores.
    * @param prices The prices of apples at each store.
    * @param roads The road network information.
    * @return An array where ans[i] is the minimum cost starting from store i.
    */
  def n(n: Long, prices: Array[Long], roads: Array[Array[Long]]): Array[Long] = {
    val numStores = n.toInt

    // Build adjacency list for the graph
    // adj[u] stores tuples: (v, cost_no_apple, cost_with_apple_multiplier)
    val adj = Array.ofDim[ArrayBuffer[(Int, Long, Long)]](numStores)
    for (i <- 0 until numStores) {
      adj[i] = ArrayBuffer()
