      val u = road(0).toInt
      val v = road(1).toInt
      val cost = road(2)
      val tax = road(3)

      // Road is bidirectional
      // Edge u -> v:
      // No apple: cost
      // With apple: cost * tax
      adj[u] += (v, cost, tax)

      // Edge v -> u:
      adj[v] += (u, cost, tax)
    }

    // 1. Calculate minimum travel cost from any node j to any node i (Empty Hand -> Store j)
    // This is equivalent to finding the shortest path from all nodes to all other nodes 
    // using only 'cost_no_apple' edges.

    // dist_empty[j][i]: minimum cost to travel from j (start) to i (target) without apples.
    // Since roads are bidirectional, and we need shortest path between all pairs, Floyd-Warshall or N Dijkstra's runs.
    // Given N <= 1000, N Dijkstra's runs (O(N * (E + N log N))) should be acceptable if E is small (E <= 2000).

    // Let's use Dijkstra's N times, starting from each potential purchase location j.

    // dist_empty[j][i]: shortest path from j to i (empty hand)
    val distEmpty = Array.ofDim[Array[Long]](numStores) { new Array[Long](numStores) }
    val INF = MaxValue

    for (startNode <- 0 until numStores) {
      val dist = new Array[Long](numStores) { INF }
      dist(startNode) = 0L

      // Min-priority queue: (cost, node)
      val pq = java.util.PriorityQueue.createWithComparator(
        (a, b) => a._1.compareTo(b._1)
      )
      pq.add((0L, startNode))

      while (!pq.isEmpty()) {
        val (d, u) = pq.poll()

        if (d > dist(u)) continue

        // Traverse using only 'cost_no_apple'
        for ((v, costNoApple, _) <- adj(u)) {
          val newDist = d + costNoApple
          if (newDist < dist(v)) {
            dist(v) = newDist
            pq.add((newDist, v))
          }
        }
      }
      distEmpty(startNode) = dist
    }

