    // Returning to i (Full): cost_with_apple = cost_no_apple * tax

    // Since the return path is from j to i, and we are calculating the cost of the *return* trip, 
    // we need the shortest path from j to i using the multiplied costs.

    // Let's run Dijkstra's N times again, starting from each potential purchase location j,
    // but this time using the 'cost_with_apple' for all edges.

    // distFull[j][i]: shortest path from j to i (full hand)
    val distFull = Array.ofDim[Array[Long]](numStores) { new Array[Long](numStores) }

    for (startNode <- 0 until numStores) {
      val dist = new Array[Long](numStores) { INF }
      dist(startNode) = 0L

