                      dist(v_neighbor) = newDist
                      pq.add((newDist, v_neighbor))
                  }
                  break // Found the edge to v, move on
              }
          }
        }
      }
      distFull(startNode) = dist
    }

    // 3. Calculate the final answer for each store i
    val ans = new Array[Long](numStores)

    for (i <- 0 until numStores) { // Target store i (where we buy apples)
      // Option 1: Buy directly at i
      var minCost = prices(i)

      // Option 2: Go to j, buy at j, return to i
      // Total Cost = Price[j] + Path(j->i, Full Hand) + Path(j->i, Empty Hand)
      // Wait, the problem states:
      // 1. Empty hand path: i -> j (Cost_empty_i_to_j)
      // 2. Purchase at j: Price[j]
      // 3. Full hand path: j -> i (Cost_full_j_to_i)
      // Total Cost = Cost_empty_i_to_j + Price[j] + Cost_full_j_to_i

      // Cost_empty_i_to_j is distEmpty[i][j] (Shortest path from i to j using no-apple cost)
      // Cost_full_j_to_i is distFull[j][i] (Shortest path from j to i using apple cost)

