    * 2. Full trip cost (j -> i): For edge (u, v, cost, tax), cost is 'cost * tax'.
    *
    * We need two sets of shortest paths:
    * a) Shortest path using 'cost' for all edges (Empty travel cost).
    * b) Shortest path using 'cost * tax' for all edges (Full travel cost).
    *
    * The problem structure allows us to simplify the travel costs for a fixed origin i:
    * For a specific target j, the total cost is: prices[j] + D_empty(i, j) + D_full(j, i).
    *
    * Since we need this for all i, we should run Dijkstra's algorithm from all possible sources or use a structure that allows efficient querying.
    *
    * Let's calculate:
    * 1. Dist_Empty[i][j]: Shortest path from i to j using only 'cost'.
    * 2. Dist_Full[i][j]: Shortest path from i to j using 'cost * tax'.
    *
    * Since the roads are bidirectional, Dist_Empty[i][j] = Dist_Empty[j][i], and Dist_Full[i][j] = Dist_Full[j][i].
    *
    * Total cost for shop i using source j: prices[j] + Dist_Empty[i][j] + Dist_Full[i][j]
    *
    * We need to run Dijkstra N times for each graph setup (Empty and Full).
    */
  def solve(n: Long, prices: Array[Long], roads: Array[Array[Long]]): Array[Long] = {
    val N = n.toInt
    val P = prices.map(_.toLong).toArray

    // --- Graph Construction ---
    // Adj list: Map from node -> List of (neighbor, weight)

    // Graph for Empty travel (Weight = cost)
    val adjEmpty = Array.fill(N)(ArrayBuffer[(Int, Long)]())

    // Graph for Full travel (Weight = cost * tax)
    val adjFull = Array.fill(N)(ArrayBuffer[(Int, Long)]())

    for (road in roads) {
      val u = road(0).toInt
      val v = road(1).toInt
      val cost = road(2)
      val tax = road(3)

      val emptyCost = cost
      val fullCost = cost * tax

      // Bidirectional roads
      adjEmpty(u).append((v, emptyCost))
      adjEmpty(v).append((u, emptyCost))

      adjFull(u).append((v, fullCost))
      adjFull(v).append((u, fullCost))
    }

    // --- Dijkstra Implementation ---

    // Runs Dijkstra's from a single source node 'startNode' on the given adjacency list
    def dijkstra(startNode: Int, adj: Array[ArrayBuffer[(Int, Long)]]): Array[Long] = {
      val dist = Array.fill(N)(MaxValue)
      val pq = new PriorityQueue[Pair[Long, Int]]() // (distance, node)

      dist(startNode) = 0
      pq.enqueue((0, startNode))

      while (!pq.isEmpty()) {
        val (d, u) = pq.dequeue()

        if (d > dist(u)) continue

        for ((v, weight) <- adj(u)) {
          val newDist = dist(u) + weight
          if (newDist < dist(v)) {
            dist(v) = newDist
            pq.enqueue((newDist, v))
          }
        }
      }
      dist
    }

    // 1. Calculate all-pairs shortest paths (or rather, N single-source shortest paths)
    // DistEmpty[i][j]: Shortest path from i to j using empty travel cost
    val distEmptyMatrix = Array.fill(N)(Array[Long](N) { _ => MaxValue })
    // DistFull[i][j]: Shortest path from i to j using full travel cost
    val distFullMatrix = Array.fill(N)(Array[Long](N) { _ => MaxValue })

    for (i <- 0 until N) {
      // Run Dijkstra on the Empty Graph starting at i
      val distEmptyFromI = dijkstra(i, adjEmpty)
      for (j <- 0 until N) {
        distEmptyMatrix(i)(j) = distEmptyFromI(j)
      }

      // Run Dijkstra on the Full Graph starting at i
      val distFullFromI = dijkstra(i, adjFull)
      for (j <- 0 until N) {
        distFullMatrix(i)(j) = distFullFromI(j)
      }
    }

    // --- Final Calculation ---
    val ans = Array.fill(N)(0L)

    for (i <- 0 until N) {
      // Option 1: Buy at shop i directly
      var minCost = P(i)

      // Option 2: Travel to shop j, buy there, travel back to i
      for (j <- 0 until N) {
        if (i == j) continue

        // Cost = prices[j] + Travel_Empty(i -> j) + Travel_Full(j -> i)

        val travelEmpty_i_to_j = distEmptyMatrix(i)(j)
        val travelFull_j_to_i = distFullMatrix(j)(i) // Since roads are bidirectional, this is the path from j to i when full

        // Check for reachability
        if (travelEmpty_i_to_j == MaxValue || travelFull_j_to_i == MaxValue) {
          continue // Cannot complete the round trip
        }

        // Total cost = Price at j + Empty trip cost (i->j) + Full trip cost (j->i)
        val totalCost = P(j) + travelEmpty_i_to_j + travelFull_j_to_i

        if (totalCost < minCost) {
          minCost = totalCost
        }
      }

      ans(i) = minCost
    }

    ans
  }
}
